const items = $input.all();
if (!items || items.length === 0) {
  return [{ json: { accountIds: '', churnRows: [] } }];
}
const ids = items.map(i => i.json.account_id).filter(Boolean);
const uniqueIds = [...new Set(ids)];
const inClause = uniqueIds.map(id => `'${id}'`).join(', ');
const churnRows = items.map(i => i.json);
return [{ json: { accountIds: inClause, churnRows } }];

const items = $input.all();
const sfRecords = items.map(i => i.json).filter(i => i && i.Guesty_Admin_ID__c);
const ownerMap = {};
for (const rec of sfRecords) {
  ownerMap[rec.Guesty_Admin_ID__c] = (rec.Owner && rec.Owner.Name) ? rec.Owner.Name : 'N/A';
}
const prevData = $('Build SOQL IN Clause').first().json;
const churnRows = prevData.churnRows || [];
if (churnRows.length === 0) {
  return [{ json: { message: ':white_check_mark: *Daily Churn Report* -- No churned accounts in the last 30 days.' } }];
}
const totalMrr = churnRows.reduce((sum, r) => sum + (r.avg_mrr || 0), 0);
const top20 = churnRows.slice(0, 20);
const today = new Date().toISOString().slice(0, 10);
const lines = [];
lines.push(':rotating_light: *Daily Churn Report* -- Last 30 Days (' + today + ')');
lines.push('*Total churned accounts:* ' + churnRows.length + '  |  *Total avg MRR lost:* $' + Math.round(totalMrr).toLocaleString());
lines.push('');
lines.push('*Account* | Churn Date | Reason | CSM | SF Owner | MRR | Segment | Geo');
lines.push('---');
for (const r of top20) {
  const owner = ownerMap[r.account_id] || 'N/A';
  const mrr = r.avg_mrr ? '$' + Math.round(r.avg_mrr).toLocaleString() : 'N/A';
  const reason = r.churn_reason_modified || r.churn_reason || 'N/A';
  lines.push('*' + r.account_name + '* | ' + r.from_date + ' | ' + reason + ' | ' + (r.csm || 'N/A') + ' | ' + owner + ' | ' + mrr + ' | ' + (r.account_segmentation || 'N/A') + ' | ' + (r.geo_area || 'N/A'));
}
if (churnRows.length > 20) {
  lines.push('_...and ' + (churnRows.length - 20) + ' more accounts. Showing top 20 by churn date._');
}
return [{ json: { message: lines.join('\n') } }];
